def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            base_score = ratio ** 4
            penalty = 0
            for k in range(1, 6):
                penalty += ((-1) ** k) * (ratio ** (k * 2)) / (k * 3)
            priorities[i] = base_score + abs(penalty) * 2
            if capacity < item / 2:
                priorities[i] += capacity * 0.5
        elif 1 < ratio <= 2:
            score = 0
            for _ in range(3):
                temp = 0
                for j in range(1, 7):
                    sign = 1 if (j % 3) != 0 else -1
                    temp += sign * (ratio ** j) / (j + 1)
                score += abs(temp)
            priorities[i] = score / 3 * 8
            if ratio > 1.8:
                extra = 0
                for m in range(2, 5):
                    extra += (ratio ** m) / (m * 2)
                priorities[i] += extra
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 10):
                sign = -1 if j % 4 == 0 else 1
                term = sign * (ratio ** j) / (j ** 1.5)
                score += term
            multiplier = 20 if ratio < 0.25 else 15 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.9:
                extra = 0
                for m in range(1, 6):
                    extra += (ratio ** m) / (m + 2)
                priorities[i] += extra * 2
            if capacity % 2 == 1:
                priorities[i] *= 1.1
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if capacity > 0 and abs(capacity - item) < 0.01:
            priorities[i] -= 1
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
